class Solution:
    def canBeValid(self, s, locked):
        n = len(s)
        if n % 2 != 0:
            return False
        reachable = {0}
        for i in range(n):
            nxt = set()
            for bal in reachable:
                if locked[i] == '1':
                    nb = bal + 1 if s[i] == '(' else bal - 1
                    if nb >= 0:
                        nxt.add(nb)
                else:
                    if bal + 1 <= n:
                        nxt.add(bal + 1)
                    if bal - 1 >= 0:
                        nxt.add(bal - 1)
            reachable = nxt
            if not reachable:
                return False
        return 0 in reachable

