class Solution:
    def canBeValid(self, s, locked):
        n = len(s)
        if n % 2 != 0:
            return False
        open_needed = 0
        for i in range(n):
            if locked[i] == '1' and s[i] == ')':
                open_needed -= 1
            else:
                open_needed += 1
            if open_needed < 0:
                return False
        close_needed = 0
        for i in range(n - 1, -1, -1):
            if locked[i] == '1' and s[i] == '(':
                close_needed -= 1
            else:
                close_needed += 1
            if close_needed < 0:
                return False
        return True

