var canBeValid = function(s, locked) {
    const n = s.length;
    if (n % 2 !== 0) return false;
    let openNeeded = 0;
    for (let i = 0; i < n; i++) {
        if (locked[i] === '1' && s[i] === ')') {
            openNeeded--;
        } else {
            openNeeded++;
        }
        if (openNeeded < 0) return false;
    }
    let closeNeeded = 0;
    for (let i = n - 1; i >= 0; i--) {
        if (locked[i] === '1' && s[i] === '(') {
            closeNeeded--;
        } else {
            closeNeeded++;
        }
        if (closeNeeded < 0) return false;
    }
    return true;
};
